<script>
import { Select, Option } from 'element-ui'
import { Table, TableColumn, Tooltip } from 'element-ui'

export default {
  components: {
    [Select.name]: Select,
    [Option.name]: Option,
    [Tooltip.name]: Tooltip,
    [Table.name]: Table,
    [TableColumn.name]: TableColumn
  },
  created(){
    this.loadPlans()
  },
  data() {
    return {
      modals : {
        modalDependent : false
      },
      plans : [],
      dependent: {
          name : null,
          cpf : null,
          dateOfBirth : null,
          email: null
      },
      brands : [
        {label: 'Visa', value: 'VISA'},
        {label: 'MasterCard', value: 'MASTERCARD'},
        {label: 'Elo', value: 'ELO'},
        {label: 'American', value: 'AMEX'},
        {label: 'Hipercard', value: 'HIPERCARD'},
        {label: 'Outros', value: 'OUTROS'},
      ],
      paymentTypes : [
        {label: 'Cartão de Crédito', value: 'CREDIT_CARD'},
        {label: 'Cartão de Débito', value: 'DEBIT_CARD'},
        {label: 'Boleto Bancário', value: 'TICKET'},
        {label: 'Carnê', value: 'TICKETS'}
      ],
      paymentDays : [
        {label: 'Dia 5', value: '5'},
        {label: 'Dia 10', value: '10'},
        {label: 'Dia 15', value: '15'},
        {label: 'Dia 20', value: '20'},
        {label: 'Dia 25', value: '25'}
      ],
      brokers : [
           {label: 'João do Pulo', value: '1'}
      ],
      companies : [
          {label: 'Filial 1', value: '1'},
          {label: 'Filial 2', value: '2'}
      ],
      validated: false,
      subscription: {
        brokerId: null,
        companyId: null,
        planId: null,
        dayForPayment: null,
        paymentType: null,
        dependents: [],
        creditCard:{
            brand: null,
            number: null,
            validate: null,
            name: null,
            securityCode: null
        },
        holder: {
          id: null,  
          cpfCnpj: '',
          name: '',
          dateOfBirth: '',
          sex: 'MALE',
          email: '',
          cellPhone: '',
          homePhone: '',
          zipcode: '',
          address: '',
          complementAddress: '',
          uf: '',
          city: '',
          neighborhood: '', 
          isHolder: true  
        }
      }
    };
  },
  methods: {
    salvarAssinatura() {
        try {
            this.$validator.validateAll()
        } finally {
            this.validated = true;
        }

        if(this.validated){
          this.$clubApi.put('/subscription', this.subscription)
          .then((response) => {
              location.href = '/assinatura/'+response.data.object.id
          }) .catch((error) => {
             this.$notify({type: 'warning', message: error.response.data.msg})
          })
        }
    },
    loadPlans(){
         this.$clubApi.get('/plan/list/active')
        .then((response) => {
           this.plans = response.data.object
        }) .catch(() => {
           this.$notify({type: 'warning', message: 'Erro ao carregar listagem de planos disponiveis.'})
        }) 
    },
    addDependent(){
        this.subscription.dependents.push({
            name : this.dependent.name,
            cpf : this.dependent.cpf,
            dateOfBirth : this.dependent.dateOfBirth,
            email : this.dependent.email
        })
        this.dependent = {
            name : '',
            cpf : '',
            dateOfBirth : '',
            email : ''
        }
        this.modals.modalDependent = false
    },
    validateZipcode(){
        var zipcode = this.subscription.holder.zipcode.replace("-","")
        this.$clubApi.get('/utils/zipcode/'+ zipcode)
        .then((response) => {
            this.subscription.holder.address = response.data.object.logradouro;
            this.subscription.holder.uf = response.data.object.uf;
            this.subscription.holder.city = response.data.object.localidade;
            this.subscription.holder.neighborhood = response.data.object.bairro;
        })
    }
  }
};
</script>
